from collections import defaultdict

def detect_tool_loops(agent):
    tool_history = agent.tool_calls[-20:]  # Last 20 calls
    tool_sequences = defaultdict(list)

    for i, call in enumerate(tool_history):
        seq = tuple(call.tool_name for call in tool_history[max(0, i-4):i+1])
        tool_sequences[seq].append(i)

    cycles = {seq: indices for seq, indices in tool_sequences.items() if len(indices) > 3}
    return len(cycles) > 0, cycles

