class LoopSafeAgent(Agent):
    def execute_tool(self, tool_call):
        args_hash = hashlib.md5(str(tool_call.args).encode()).hexdigest()
        cache_key = (tool_call.tool_name, args_hash)

        if cache_key in self.visited_states:
            return {'result': 'LOOP_DETECTED: Skipping repeated tool call', 'cached': True}

        self.visited_states.add(cache_key)
        return super().execute_tool(tool_call)

from pydantic_ai import Agent

class LoopProtectedAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.tool_cycles = defaultdict(int)
        self.max_cycle_threshold = 3

    def run(self, max_iterations=20):
        for i in range(max_iterations):
            if self.detect_imminent_loop():
                return {'status': 'LOOP_INTERRUPTED', 'iteration': i}
            result = super().run(iterations=1)
        return result

    def detect_imminent_loop(self):
        recent_tools = [call.tool_name for call in self.tool_calls[-5:]]
        self.tool_cycles[tuple(recent_tools)] += 1
        return self.tool_cycles[tuple(recent_tools)] > self.max_cycle_threshold

from pydantic_ai import Agent

class AntiLoopAgent(Agent):
    def update_system_prompt(self):
        cycles_detected = len(self.tool_cycles) if hasattr(self, 'tool_cycles') else 0
        anti_loop_prompt = (
            f"⚠️ DETECTED {cycles_detected} POTENTIAL LOOPS. "
            f"Do NOT repeat recent tools. Try completely different approach. "
            f"Previous tools (avoid): {list(self.tool_cycles.keys())[:3]}"
        )
        self.system_prompt += f'\n\n{anti_loop_prompt}'
